SELECT * FROM(
SELECT @RN:=@RN+1 AS rnum, a.* FROM(
SELECT * From Board
WHERE `DELETE` = 0
AND category <> 'Faq'

    AND Subject = #{subject}

ORDER BY PostNum DESC
) a, (SELECT @RN:=0) b
) c WHERE c.rnum BETWEEN #{begin} AND #{end}

