UPDATE Board SET Subject = #{subject}, Content = #{content}, Category = #{category}, ModDate = NOW()
,FileName = #{FileName}
WHERE PostNum = #{PostNum}

UPDATE Board
SET ThumbsUp = ThumbsUp + 1
WHERE PostNum = #{PostNum}

